public struct PgpPublicKeyInfo {
    public var fingerprint: String
    public var uids: [String]
    public var createdAtUnix: Int64
    public var expiresAtUnix: Int64?
    public var isExpired: Bool
    public var isRevoked: Bool
    public var canEncrypt: Bool

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(fingerprint: String, uids: [String], createdAtUnix: Int64, expiresAtUnix: Int64?, isExpired: Bool, isRevoked: Bool, canEncrypt: Bool) {
        self.fingerprint = fingerprint
        self.uids = uids
        self.createdAtUnix = createdAtUnix
        self.expiresAtUnix = expiresAtUnix
        self.isExpired = isExpired
        self.isRevoked = isRevoked
        self.canEncrypt = canEncrypt
    }
}



extension PgpPublicKeyInfo: Equatable, Hashable {
    public static func ==(lhs: PgpPublicKeyInfo, rhs: PgpPublicKeyInfo) -> Bool {
        if lhs.fingerprint != rhs.fingerprint {
            return false
        }
        if lhs.uids != rhs.uids {
            return false
        }
        if lhs.createdAtUnix != rhs.createdAtUnix {
            return false
        }
        if lhs.expiresAtUnix != rhs.expiresAtUnix {
            return false
        }
        if lhs.isExpired != rhs.isExpired {
            return false
        }
        if lhs.isRevoked != rhs.isRevoked {
            return false
        }
        if lhs.canEncrypt != rhs.canEncrypt {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(fingerprint)
        hasher.combine(uids)
        hasher.combine(createdAtUnix)
        hasher.combine(expiresAtUnix)
        hasher.combine(isExpired)
        hasher.combine(isRevoked)
        hasher.combine(canEncrypt)
    }
}


