    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> SanctCryptoError {
        let variant: Int32 = try readInt(&buf)
        switch variant {

        

        
        case 1: return .Crypto(
            message: try FfiConverterString.read(from: &buf)
        )
        
        case 2: return .Pgp(
            message: try FfiConverterString.read(from: &buf)
        )
        

        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: SanctCryptoError, into buf: inout [UInt8]) {
        switch value {

        

        
        case .Crypto(_ /* message is ignored*/):
            writeInt(&buf, Int32(1))
        case .Pgp(_ /* message is ignored*/):
            writeInt(&buf, Int32(2))

        
        }
    }
}


